function a(A){document.title=`Percorso · ${A.titolo} · ${A.luogo}`;document.getElementById('prog-overline').textContent=A.luogo;document.getElementById('prog-subtitle').textContent=`${A.titolo} — ${A.sottotitolo}`}(async function _(){try{let b=await fetch('programma.json');a(await b.json())}catch(e){}})();
